+    #[test]
+    fn test_command_timing_breakdown_serialization() {
+        let timing = CommandTimingBreakdown {
+            classify: Some(Duration::from_millis(2)),
+            select: None,
+            sync_up: Some(Duration::from_millis(120)),
+            exec: Some(Duration::from_millis(900)),
